allow:
Bash(/c/github/web_gui/styles.css << 'EOF'

/* OS Verification Styles */
.os-test-item {
    transition: all 0.2s ease;
}

.os-test-item:hover {
    border-color: #667eea !important;
    box-shadow: 0 2px 8px rgba\(102, 126, 234, 0.15\);
    transform: translateY\(-1px\);
}

.os-test-item.test-passed {
    border-left: 4px solid #28a745;
    background: #f0fff4 !important;
}

.os-test-item.test-failed {
    border-left: 4px solid #dc3545;
    background: #fff5f5 !important;
}

.os-test-item.test-running {
    border-left: 4px solid #667eea;
    background: #f5f7ff !important;
}

.test-status-badge.status-passed {
    background: #28a745 !important;
    color: white !important;
}

.test-status-badge.status-failed {
    background: #dc3545 !important;
    color: white !important;
}

.test-status-badge.status-running {
    background: #667eea !important;
    color: white !important;
    animation: pulse 1.5s ease-in-out infinite;
}

@keyframes pulse {
    0%, 100% {
        opacity: 1;
    }
    50% {
        opacity: 0.6;
    }
}
EOF)
